&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Key terms from the Key Points:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Urban poverty rate:&lt;/strong&gt; Represents the percentage of people in urban areas living below the poverty line.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;SBI Report:&lt;/strong&gt; Published by the State Bank of India, these reports provide insights into key economic indicators and trends.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Government welfare schemes:&lt;/strong&gt; Initiatives such as PMAY (Pradhan Mantri Awas Yojana), MGNREGA (Mahatma Gandhi National Rural Employment Guarantee Act), and others aim to alleviate poverty and improve living standards.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Urbanization:&lt;/strong&gt; A process where a growing percentage of the population migrates to cities, often leading to better job opportunities and improved access to education and healthcare.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर&lt;u&gt;&lt;strong&gt; 4.09%&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;वित्तीय वर्ष 2024 भारतीय स्टेट बैंक (SBI) रिपोर्ट में उल्लिखित &lt;strong&gt;शहरी गरीबी दर&lt;/strong&gt; 4.09% है, जो गरीबी रेखा से नीचे रहने वाली शहरी आबादी के अनुपात का प्रतिनिधित्व करती है।&lt;/li&gt;
	&lt;li&gt;यह डेटा SBI के &lt;strong&gt;आर्थिक अनुसंधान विभाग&lt;/strong&gt; द्वारा एक विस्तृत विश्लेषण से प्राप्त किया गया है, जो नियमित रूप से भारत में विभिन्न आर्थिक संकेतकों पर रिपोर्ट प्रकाशित करता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;गरीबी दर&lt;/strong&gt; आर्थिक असमानता का एक महत्वपूर्ण माप है, जो भोजन, आश्रय और अन्य आवश्यक वस्तुओं के लिए अपनी बुनियादी ज़रूरतों को पूरा करने में असमर्थ लोगों के प्रतिशत को इंगित करता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सरकारी कल्याणकारी योजनाओं&lt;/strong&gt;, &lt;strong&gt;रोजगार सृजन कार्यक्रमों&lt;/strong&gt; और &lt;strong&gt;शहरीकरण&lt;/strong&gt; सहित कई कारकों के कारण भारत में शहरी गरीबी दर में पिछले कुछ वर्षों में गिरावट आई है।&lt;/li&gt;
	&lt;li&gt;रिपोर्ट शहरी निवासियों के सामने आने वाली चुनौतियों को समझने और आर्थिक असमानता को कम करने के लिए प्रभावी नीतियों को तैयार करने हेतु शहरी गरीबी पर नज़र रखने के महत्व पर प्रकाश डालती है।&lt;/li&gt;
	&lt;li&gt;SBI की रिपोर्ट को &lt;strong&gt;व्यापक डेटा स्रोतों&lt;/strong&gt; और &lt;strong&gt;सुव्यवस्थित विश्लेषण&lt;/strong&gt; के उपयोग के कारण अत्यधिक विश्वसनीय माना जाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;मुख्य बिंदुओं से प्रमुख शर्तें:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;शहरी गरीबी दर:&lt;/strong&gt; शहरी क्षेत्रों में गरीबी रेखा से नीचे रहने वाले लोगों का प्रतिशत दर्शाता है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;SBI रिपोर्ट:&lt;/strong&gt; भारतीय स्टेट बैंक द्वारा प्रकाशित, ये रिपोर्ट प्रमुख आर्थिक संकेतकों और प्रवृत्तियों में अंतर्दृष्टि प्रदान करती हैं।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;सरकारी कल्याणकारी योजनाएँ:&lt;/strong&gt; PMAY (प्रधानमंत्री आवास योजना), MGNREGA (महात्मा गांधी राष्ट्रीय ग्रामीण रोजगार गारंटी अधिनियम), और अन्य जैसी पहल का उद्देश्य गरीबी को कम करना और जीवन स्तर में सुधार करना है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;शहरीकरण:&lt;/strong&gt; एक प्रक्रिया जहाँ बढ़ती हुई जनसंख्या का प्रतिशत शहरों में प्रवास करता है, जिसके परिणामस्वरूप प्रायः बेहतर नौकरी के अवसर और शिक्षा एवं स्वास्थ्य सेवा तक बेहतर पहुँच प्राप्त होती है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Odisha.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Nabakalebara&lt;/strong&gt; is a festival celebrated in &lt;u&gt;&lt;strong&gt;Odisha&lt;/strong&gt;&lt;/u&gt; state.&lt;/li&gt;
	&lt;li&gt;It is a symbolic recreation of the wooden forms of three Hindu deities at &lt;strong&gt;Jagannath Temple, Puri.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Nabakalebara festival was first observed&amp;nbsp;in &lt;strong&gt;1575 A.D.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;It was first organised by Yaduvanshi Bhoi King &lt;strong&gt;Ramachandra Deva.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;The meaning of &amp;#39;Naba&amp;#39; is&amp;nbsp;&amp;#39;new&amp;#39; and &amp;#39;Kalebara&amp;#39; is &amp;#39;body&amp;#39;.&lt;/li&gt;
	&lt;li&gt;Nabakalebara&amp;nbsp;celebrating&lt;span style=&quot;color: (0, 0, 0);   text-align: justify;&quot;&gt; in 8 years or 16 years or 19 years depending on the auspicious day.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;In the 20th century, the Nabakalebara function was celebrated in the Temple in 1912, 1931, 1950, 1969, 1977 and 1996.&lt;/li&gt;
	&lt;li&gt;The last&amp;nbsp;Nabakalebara festival was celebrated in&lt;strong&gt; 2015.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Bihu is the most important festival of&lt;strong&gt; Assam.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Saga Dawa&amp;nbsp;is the most important festival of &lt;strong&gt;Sikkim.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Durga Puja is the most important festival of &lt;strong&gt;West Bengal.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्&amp;zwj;तर&amp;nbsp;&lt;u&gt;&lt;strong&gt;ओडिशा &lt;/strong&gt;&lt;/u&gt;है।&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;नवकलेबारा &lt;u&gt;ओडिशा &lt;/u&gt;&lt;/strong&gt;राज्य में मनाया जाने वाला एक त्योहार है।&lt;/li&gt;
	&lt;li&gt;यह &lt;strong&gt;जगन्नाथ मंदिर, पुरी&lt;/strong&gt; में तीन हिंदू देवताओं के लकड़ी के रूपों का एक प्रतीकात्मक मनोरंजन है।&lt;/li&gt;
	&lt;li&gt;नवकलेबारा उत्सव पहली बार &lt;strong&gt;1575 ई&lt;/strong&gt;. में मनाया गया था।&lt;/li&gt;
	&lt;li&gt;इसका आयोजन सबसे पहले यदुवंशी भोई राजा &lt;strong&gt;रामचंद्र देव&lt;/strong&gt; ने किया था।&lt;/li&gt;
	&lt;li&gt;&amp;#39;नबा&amp;#39; का अर्थ &amp;#39;नया&amp;#39; है और &amp;#39;कालेबरा&amp;#39; का अर्थ है &amp;#39;शरीर&amp;#39;।&lt;/li&gt;
	&lt;li&gt;नवकलेबारा शुभ दिन के आधार पर 8 वर्ष या 16 वर्ष या 19 वर्ष में मनाया जाता है।&lt;/li&gt;
	&lt;li&gt;20वीं शताब्दी में, मंदिर में 1912, 1931, 1950, 1969, 1977 और 1996 में नवकलेबारा समारोह मनाया गया।&lt;/li&gt;
	&lt;li&gt;पिछला नवकलेबारा उत्सव 2015 में मनाया गया था।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;बिहू &lt;strong&gt;असम &lt;/strong&gt;का सबसे महत्वपूर्ण त्योहार है।&lt;/li&gt;
	&lt;li&gt;सागा दावा &lt;strong&gt;सिक्किम &lt;/strong&gt;का सबसे महत्वपूर्ण त्योहार है।&lt;/li&gt;
	&lt;li&gt;जमाई षष्ठी &lt;strong&gt;पश्चिम बंगाल &lt;/strong&gt;का सबसे महत्वपूर्ण त्योहार है।&lt;/li&gt;
&lt;/ul&gt;

questions.statement:
&lt;p&gt;Consider the following statements regarding the Graded Response Action Plan (GRAP):&lt;/p&gt;

&lt;p&gt;Statement I: The Graded Response Action Plan (GRAP) was implemented by the Commission for Air Quality Management (CAQM) to combat air pollution in the National Capital Region (NCR) through stage-wise interventions based on AQI levels.&lt;/p&gt;

&lt;p&gt;Statement II: GRAP was established under the National Clean Air Programme (NCAP) in 2019 to provide legal powers to state pollution control boards for emergency response.&lt;/p&gt;

&lt;p&gt;Which one of the following is correct in respect of the above statements?&lt;/p&gt;<br>&lt;p&gt;ग्रेडेड रिस्पांस एक्शन प्लान (GRAP) के संबंध में निम्नलिखित कथनों पर विचार करें:&lt;/p&gt;

&lt;p&gt;कथन I: ग्रेडेड रिस्पांस एक्शन प्लान (GRAP) को वायु गुणवत्ता सूचकांक (AQI) के स्तरों के आधार पर चरण-वार हस्तक्षेपों के माध्यम से राष्ट्रीय राजधानी क्षेत्र (NCR) में वायु प्रदूषण से निपटने के लिए वायु गुणवत्ता प्रबंधन आयोग (CAQM) द्वारा कार्यान्वित किया गया था।&lt;/p&gt;

&lt;p&gt;कथन II: GRAP की स्थापना राष्ट्रीय स्वच्छ वायु कार्यक्रम (NCAP) के तहत 2019 में राज्य प्रदूषण नियंत्रण बोर्डों को आपातकालीन प्रतिक्रिया के लिए कानूनी अधिकार प्रदान करने के लिए की गई थी।&lt;/p&gt;

&lt;p&gt;उपरोक्त कथनों के संबंध में निम्नलिखित में से कौन सा सही है?&lt;/p&gt;

questions.explanation:
&lt;p&gt;The correct answer is &lt;strong&gt;Option 3&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;The Delhi government has implemented Stage III of the Graded Response Action Plan (GRAP-III) as the city&amp;rsquo;s Air Quality Index (AQI) breached 400 (&amp;lsquo;severe&amp;rsquo; category) for the first time in the 2025 winter season.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;The Graded Response Action Plan (GRAP) is a dynamic framework implemented by the Commission for Air Quality Management (CAQM) in coordination with the Central Pollution Control Board (CPCB), Delhi Government, and NCR state boards.It prescribes stage-wise actions (Stages I&amp;ndash;IV) based on AQI levels to reduce air pollution in the NCR. &lt;strong&gt;Hence, Statement I is correct. &lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;GRAP was not established under NCAP (2019); it was formulated in 2017 following Supreme Court directions, based on recommendations by the Environment Pollution (Prevention and Control) Authority (EPCA). Its legal backing came from the Air (Prevention and Control of Pollution) Act, 1981, not the NCAP. &lt;strong&gt;Hence, Statement II is incorrect.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;Objective:&lt;/strong&gt; To reduce air pollution in &lt;strong&gt;Delhi-NCR&lt;/strong&gt; through &lt;strong&gt;timely, coordinated, and graded interventions&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Stages: &lt;/strong&gt;
	&lt;ul style=&quot;list-style-type: circle;&quot;&gt;
		&lt;li&gt;Stage I (Poor AQI: 201&amp;ndash;300)&lt;/li&gt;
		&lt;li&gt;Stage II (Very Poor AQI: 301&amp;ndash;400)&lt;/li&gt;
		&lt;li&gt;Stage III (Severe AQI: 401&amp;ndash;450)&lt;/li&gt;
		&lt;li&gt;Stage IV (Severe+ AQI: &amp;gt;450)&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Measures under Stage III:&lt;/strong&gt; Ban on construction and demolition activities, restrictions on diesel gensets, increased mechanized road cleaning, and traffic curbs.&lt;/li&gt;
	&lt;li&gt;GRAP supports &lt;strong&gt;NCAP objectives&lt;/strong&gt;, though it predates NCAP and operates as a &lt;strong&gt;crisis-response mechanism&lt;/strong&gt; rather than a long-term pollution control plan.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;strong&gt;विकल्प 3&lt;/strong&gt; है&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;समाचार में&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;दिल्ली सरकार ने ग्रेडेड रिस्पांस एक्शन प्लान (GRAP-III) का चरण III लागू किया है क्योंकि शहर का वायु गुणवत्ता सूचकांक (AQI) 2025 के शीतकालीन सत्र में पहली बार 400 (&amp;#39;गंभीर&amp;#39; श्रेणी) को पार कर गया है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;मुख्य बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;ग्रेडेड रिस्पांस एक्शन प्लान (GRAP) एक गतिशील ढांचा है जिसे केंद्रीय प्रदूषण नियंत्रण बोर्ड (CPCB), दिल्ली सरकार और NCR राज्य बोर्डों के समन्वय में वायु गुणवत्ता प्रबंधन आयोग (CAQM) द्वारा कार्यान्वित किया जाता है। यह NCR में वायु प्रदूषण को कम करने के लिए AQI स्तरों के आधार पर चरण-वार कार्यों (चरण I-IV) को निर्धारित करता है। &lt;strong&gt;इसलिए, कथन I सही है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;GRAP की स्थापना NCAP (2019) के तहत नहीं की गई थी; इसे पर्यावरण प्रदूषण (रोकथाम और नियंत्रण) प्राधिकरण (EPCA) की सिफारिशों के आधार पर, सर्वोच्च न्यायालय के निर्देशों के बाद 2017 में तैयार किया गया था। इसकी कानूनी सहायता वायु (प्रदूषण की रोकथाम और नियंत्रण) अधिनियम, 1981 से आई थी, न कि NCAP से। &lt;strong&gt;इसलिए, कथन II गलत है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;उद्देश्य:&lt;/strong&gt; &lt;strong&gt;समय पर, समन्वित और श्रेणीबद्ध हस्तक्षेपों&lt;/strong&gt; के माध्यम से &lt;strong&gt;दिल्ली-NCR&lt;/strong&gt; में वायु प्रदूषण को कम करना।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;चरण:&lt;/strong&gt;
	&lt;ul style=&quot;list-style-type: circle;&quot;&gt;
		&lt;li&gt;चरण I (खराब AQI: 201-300)&lt;/li&gt;
		&lt;li&gt;चरण II (बहुत खराब AQI: 301-400)&lt;/li&gt;
		&lt;li&gt;चरण III (गंभीर AQI: 401-450)&lt;/li&gt;
		&lt;li&gt;चरण IV (गंभीर+ AQI: &amp;gt;450)&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;चरण III के तहत उपाय:&lt;/strong&gt; निर्माण और विध्वंस गतिविधियों पर प्रतिबंध, डीजल जेनसेट पर प्रतिबंध, मशीनीकृत सड़क की सफाई में वृद्धि और यातायात पर अंकुश।&lt;/li&gt;
	&lt;li&gt;GRAP &lt;strong&gt;NCAP उद्देश्यों&lt;/strong&gt; का समर्थन करता है, हालांकि यह NCAP से पहले का है और एक दीर्घकालिक प्रदूषण नियंत्रण योजना के बजाय एक &lt;strong&gt;संकट-प्रतिक्रिया तंत्र&lt;/strong&gt; के रूप में काम करता है।&lt;/li&gt;
&lt;/ul&gt;

questions.statement:
&lt;p&gt;With reference to the Asian Development Bank (ADB), consider the following statements:&lt;/p&gt;

&lt;p&gt;I. ADB follows a weighted voting system where voting power is linked to shareholding.&lt;/p&gt;

&lt;p&gt;II. India is among the top five borrowers of ADB in terms of loan assistance.&lt;/p&gt;

&lt;p&gt;III. The Asian Development Fund (ADF), managed by ADB, provides concessional loans to the poorest member countries.&lt;/p&gt;

&lt;p&gt;IV. All member countries of ADB are located within the Asia-Pacific region.&lt;/p&gt;

&lt;p&gt;How many of the above statements are correct?&lt;/p&gt;<br>&lt;p&gt;एशियाई विकास बैंक (ADB) के संदर्भ में, निम्नलिखित कथनों पर विचार करें:&lt;/p&gt;

&lt;p&gt;I. ADB एक भारित मतदान प्रणाली का पालन करता है जहाँ मतदान शक्ति शेयरधारिता से जुड़ी होती है।&lt;/p&gt;

&lt;p&gt;II. ऋण सहायता के मामले में भारत ADB के शीर्ष पाँच उधारकर्ताओं में से एक है।&lt;/p&gt;

&lt;p&gt;III. ADB द्वारा प्रबंधित एशियाई विकास कोष (ADF), सबसे गरीब सदस्य देशों को रियायती ऋण प्रदान करता है।&lt;/p&gt;

&lt;p&gt;IV. ADB के सभी सदस्य देश एशिया-प्रशांत क्षेत्र के भीतर स्थित हैं।&lt;/p&gt;

&lt;p&gt;उपरोक्त में से कितने कथन सही हैं?&lt;/p&gt;

questions.explanation:
&lt;p&gt;The correct answer is &lt;strong&gt;Option 3 &lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;The India&amp;ndash;ADB loan highlights India&amp;rsquo;s strong borrowing relationship with ADB.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;ADB&amp;rsquo;s governance is based on shareholding; Japan and USA are largest shareholders. &lt;strong&gt;Hence, Statement I is correct. &lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;India is one of the top borrowers, mainly for infrastructure, energy, and development projects. &lt;strong&gt;Hence, Statement II is correct. &lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;ADF provides soft loans and grants to poorer nations. &lt;strong&gt;Hence, Statement III is correct. &lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;ADB has non-Asian members too (e.g., USA, Canada, European countries). &lt;strong&gt;Hence, Statement IV is incorrect. &lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;ADB has 68 members, of which 49 are from Asia-Pacific.&lt;/li&gt;
	&lt;li&gt;It works alongside World Bank and AIIB in Asia.&lt;/li&gt;
	&lt;li&gt;India uses ADB loans for metro projects, energy transitions, and tourism.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;strong&gt;विकल्प 3&lt;/strong&gt; है&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;समाचार में&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;भारत-ADB ऋण भारत और ADB के बीच मजबूत ऋण संबंधों को उजागर करता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;मुख्य बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;ADB का शासन शेयरधारिता पर आधारित है; जापान और अमेरिका सबसे बड़े शेयरधारक हैं। &lt;strong&gt;इसलिए, कथन I सही है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;भारत शीर्ष उधारकर्ताओं में से एक है, मुख्य रूप से बुनियादी ढाँचे, ऊर्जा और विकास परियोजनाओं के लिए। &lt;strong&gt;इसलिए, कथन II सही है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;ADF गरीब राष्ट्रों को नरम ऋण और अनुदान प्रदान करता है। &lt;strong&gt;इसलिए, कथन III सही है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;ADB में गैर-एशियाई सदस्य भी हैं (जैसे, अमेरिका, कनाडा, यूरोपीय देश)। &lt;strong&gt;इसलिए, कथन IV गलत है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;ADB के 68 सदस्य हैं, जिनमें से 49 एशिया-प्रशांत से हैं।&lt;/li&gt;
	&lt;li&gt;यह एशिया में विश्व बैंक और AIIB के साथ मिलकर काम करता है।&lt;/li&gt;
	&lt;li&gt;भारत मेट्रो परियोजनाओं, ऊर्जा संक्रमण और पर्यटन के लिए ADB ऋण का उपयोग करता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;CSIR-CSIO&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-size: 21px; font-weight: bolder; font-family: var(--bs-body-font-family); text-align: var(--bs-body-text-align);&quot;&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;CSIR-CSIO (Central Scientific Instruments Organisation)&lt;/strong&gt; has developed the Induct UV-C disinfectant system.&lt;/li&gt;
	&lt;li&gt;This system is designed to disinfect HVAC (Heating, Ventilation, and Air Conditioning) ducts in mechanically ventilated indoor spaces.&lt;/li&gt;
	&lt;li&gt;The disinfectant system uses &lt;strong&gt;UV-C light technology&lt;/strong&gt; to eliminate viruses, bacteria, fungi, and mold, including Covid-19-like pathogens.&lt;/li&gt;
	&lt;li&gt;The technology is aimed at ensuring safer indoor environments in public and private spaces such as offices, malls, and hospitals during and post-pandemic.&lt;/li&gt;
	&lt;li&gt;CSIR-CSIO is one of the constituent laboratories of the &lt;strong&gt;Council of Scientific and Industrial Research (CSIR)&lt;/strong&gt;, which focuses on advanced instrumentation and applied research.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;UV-C Technology&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;UV-C light is a type of ultraviolet light with wavelengths between 200-280 nanometers.&lt;/li&gt;
		&lt;li&gt;It is effective in inactivating microorganisms by breaking their DNA or RNA, preventing replication.&lt;/li&gt;
		&lt;li&gt;UV-C systems are widely used for sterilization in healthcare, water purification, and air disinfection.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;CSIR-CSIO&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Based in Chandigarh, CSIR-CSIO is a national laboratory under CSIR.&lt;/li&gt;
		&lt;li&gt;It specializes in the development of scientific instruments and applied research in fields like optics, electronics, and biomedical devices.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;HVAC Systems&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;HVAC stands for Heating, Ventilation, and Air Conditioning systems.&lt;/li&gt;
		&lt;li&gt;These systems regulate indoor temperature, air quality, and humidity levels.&lt;/li&gt;
		&lt;li&gt;Disinfection of HVAC ducts is crucial in preventing the airborne spread of pathogens.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Role of CSIR in Covid-19 Response&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;CSIR has been at the forefront of India&amp;#39;s fight against Covid-19, developing diagnostics, therapeutics, and disinfection solutions.&lt;/li&gt;
		&lt;li&gt;Its initiatives include genome sequencing, vaccine research, and the development of innovative technologies like the Induct UV-C system.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;CSIR-CSIO&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-size:22px;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; style=&quot;color: rgb(33, 37, 41);&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;color: rgb(33, 37, 41);  font-weight: bolder;&quot;&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;CSIR-CSIO (केंद्रीय वैज्ञानिक उपकरण संगठन)&lt;/strong&gt; ने इंडक्ट UV-C कीटाणुनाशक प्रणाली विकसित की है।&lt;/li&gt;
	&lt;li&gt;यह प्रणाली यांत्रिक रूप से हवादार इनडोर स्थानों में HVAC (हीटिंग, वेंटिलेशन और एयर कंडीशनिंग) नलिकाओं को कीटाणुरहित करने के लिए डिज़ाइन की गई है।&lt;/li&gt;
	&lt;li&gt;कीटाणुनाशक प्रणाली कोविड -19 जैसे रोगजनकों सहित वायरस, बैक्टीरिया, कवक और मोल्ड को खत्म करने के लिए &lt;strong&gt;UV-C प्रकाश तकनीक&lt;/strong&gt; का उपयोग करती है।&lt;/li&gt;
	&lt;li&gt;यह तकनीक महामारी के दौरान और बाद में कार्यालयों, मॉल और अस्पतालों जैसे सार्वजनिक और निजी स्थानों में सुरक्षित इनडोर वातावरण सुनिश्चित करने के उद्देश्य से है।&lt;/li&gt;
	&lt;li&gt;CSIR-CSIO, &lt;strong&gt;वैज्ञानिक और औद्योगिक अनुसंधान परिषद (CSIR)&lt;/strong&gt; की घटक प्रयोगशालाओं में से एक है, जो उन्नत उपकरण और अनुप्रयुक्त अनुसंधान पर केंद्रित है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-size:22px;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; style=&quot;color: rgb(33, 37, 41);&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;UV-C तकनीक&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;UV-C प्रकाश पराबैंगनी प्रकाश का एक प्रकार है जिसकी तरंग दैर्ध्य 200-280 नैनोमीटर के बीच होती है।&lt;/li&gt;
		&lt;li&gt;यह उनके डीएनए या आरएनए को तोड़कर सूक्ष्मजीवों को निष्क्रिय करने में प्रभावी है, जिससे प्रतिकृति रुक जाती है।&lt;/li&gt;
		&lt;li&gt;स्वास्थ्य सेवा, जल शोधन और वायु कीटाणुशोधन में UV-C प्रणालियों का व्यापक रूप से उपयोग किया जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;CSIR-CSIO&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;चंडीगढ़ में स्थित, CSIR-CSIO CSIR के अधीन एक राष्ट्रीय प्रयोगशाला है।&lt;/li&gt;
		&lt;li&gt;यह प्रकाशिकी, इलेक्ट्रॉनिक्स और जैव चिकित्सा उपकरणों जैसे क्षेत्रों में वैज्ञानिक उपकरणों के विकास और अनुप्रयुक्त अनुसंधान में विशेषज्ञता रखता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;HVAC सिस्टम&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;HVAC का अर्थ है हीटिंग, वेंटिलेशन और एयर कंडीशनिंग सिस्टम।&lt;/li&gt;
		&lt;li&gt;ये सिस्टम इनडोर तापमान, वायु गुणवत्ता और आर्द्रता के स्तर को नियंत्रित करते हैं।&lt;/li&gt;
		&lt;li&gt;रोगजनकों के हवाई प्रसार को रोकने में HVAC नलिकाओं का कीटाणुशोधन महत्वपूर्ण है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;कोविड -19 प्रतिक्रिया में CSIR की भूमिका&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;CSIR कोविड -19 के खिलाफ भारत की लड़ाई में सबसे आगे रहा है, निदान, चिकित्सा और कीटाणुशोधन समाधान विकसित कर रहा है।&lt;/li&gt;
		&lt;li&gt;इसकी पहलों में जीनोम अनुक्रमण, टीका अनुसंधान और इंडक्ट UV-C प्रणाली जैसी नवीन तकनीकों का विकास शामिल है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

